-- Script para inserir todos os operadores no Supabase
-- Execute este script no SQL Editor do Supabase

-- Limpar operadores existentes (opcional - descomente se quiser resetar)
-- DELETE FROM users WHERE role = 'operator';

-- Inserir todos os operadores
ON CONFLICT (email) DO UPDATE SET
  username = EXCLUDED.username,
  name = EXCLUDED.name,
  role = EXCLUDED.role,
  is_active = EXCLUDED.is_active,
  updated_at = NOW();

-- Verificar total de operadores inseridos
SELECT COUNT(*) as total_operadores FROM users WHERE role = 'operator';
